module top_module(
    input clk,
    input load,
    input [3:0] in,
    output [3:0] out
);reg [3:0] reg_out;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load) begin
            reg_out <= in;
        end else begin
            reg_out <= {reg_out[2:0], 1'b0};
        end
    end

    assign out = reg_out;

endmodule
